static size_t branch_offset(int h,int b){size_t off=0,hw=(size_t)PP_OUT_H*PP_OUT_W;for(int i=0;i<h;i++)for(int j=0;j<6;j++)off+=(size_t)pp_branch_channels(i,j)*hw;for(int j=0;j<b;j++)off+=(size_t)pp_branch_channels(h,j)*hw;return off;}
static const float*dt(const pp_model*m,const char*n,const uint8_t*d){for(uint32_t i=0;i<m->count;i++)if(!std::strcmp(m->records[i].name,n))return reinterpret_cast<const float*>(d+m->records[i].offset);return nullptr;}
static const __half*ht(const pp_model*m,const char*n,const __half*d){for(uint32_t i=0;i<m->count;i++)if(!std::strcmp(m->records[i].name,n))return d+m->records[i].offset/sizeof(float);return nullptr;}
__global__ void pfn(const float*f,int np,const float*w,const float*b,float*out){int id=blockIdx.x*blockDim.x+threadIdx.x;if(id>=np*64)return;int p=id/64,o=id%64;float best=0;for(int j=0;j<20;j++){const float*x=f+((size_t)p*20+j)*11;float v=b[o];for(int k=0;k<11;k++)v+=w[o*11+k]*x[k];best=fmaxf(best,v);}out[(size_t)o*np+p]=best;}
__global__ void scatter(const float*x,const int32_t*c,int np,float*y){int id=blockIdx.x*blockDim.x+threadIdx.x;if(id>=np*64)return;int o=id/np,p=id%np,iy=c[(size_t)p*4+2],ix=c[(size_t)p*4+3];y[((size_t)o*512+iy)*512+ix]=x[(size_t)o*np+p];}
__global__ void f2h(const float*x,__half*y,size_t n){size_t i=(size_t)blockIdx.x*blockDim.x+threadIdx.x;if(i<n)y[i]=__float2half(x[i]);}
__global__ void im2col_linear(const float*x,__half*y,int ci,int hi,int wi,int stride,int kernel,int pad,int npad){int ho=(hi+2*pad-kernel)/stride+1,wo=(wi+2*pad-kernel)/stride+1,n=ho*wo,kdim=ci*kernel*kernel;size_t id=(size_t)blockIdx.x*blockDim.x+threadIdx.x,total=(size_t)kdim*npad;if(id>=total)return;int p=id%npad,k=id/npad;if(p>=n){y[id]=__float2half(0);return;}int ox=p%wo,oy=p/wo,ic=k/(kernel*kernel),q=k%(kernel*kernel),iy=oy*stride+q/kernel-pad,ix=ox*stride+q%kernel-pad;float v=0;if((unsigned)iy<(unsigned)hi&&(unsigned)ix<(unsigned)wi)v=x[((size_t)ic*hi+iy)*wi+ix];y[id]=__float2half(v);}
__global__ void im2col_2d(const float*x,__half*y,int hi,int wi,int stride,int kernel,int pad,int n,int npad){int p=blockIdx.x*blockDim.x+threadIdx.x,k=blockIdx.y;if(p>=npad)return;size_t id=(size_t)k*npad+p;if(p>=n){y[id]=__float2half(0);return;}int kk=kernel*kernel,wo=(wi+2*pad-kernel)/stride+1,ox=p%wo,oy=p/wo,ic=k/kk,q=k%kk,iy=oy*stride+q/kernel-pad,ix=ox*stride+q%kernel-pad;float v=0;if((unsigned)iy<(unsigned)hi&&(unsigned)ix<(unsigned)wi)v=x[((size_t)ic*hi+iy)*wi+ix];y[id]=__float2half(v);}
static void launch_im2col(const float*x,__half*y,int ci,int hi,int wi,int stride,int kernel,int pad,int npad){int ho=(hi+2*pad-kernel)/stride+1,wo=(wi+2*pad-kernel)/stride+1,n=ho*wo,kdim=ci*kernel*kernel;static int legacy=-1;if(legacy<0)legacy=std::getenv("PP_CUDA_LEGACY_IM2COL")!=nullptr;if(legacy){size_t total=(size_t)kdim*npad;im2col_linear<<<(total+255)/256,256>>>(x,y,ci,hi,wi,stride,kernel,pad,npad);}else{dim3 grid((npad+255)/256,kdim);im2col_2d<<<grid,256>>>(x,y,hi,wi,stride,kernel,pad,n,npad);}}
__global__ void wmma_conv(const __half*w,const __half*x,float*y,const float*b,int co,int kdim,int n,int npad,int relu){using namespace nvcuda;int mt=blockIdx.y*16,nt=blockIdx.x*16;if(mt>=co||nt>=n)return;wmma::fragment<wmma::matrix_a,16,16,16,__half,wmma::row_major>a;wmma::fragment<wmma::matrix_b,16,16,16,__half,wmma::row_major>v;wmma::fragment<wmma::accumulator,16,16,16,float>c;wmma::fill_fragment(c,0);for(int k=0;k<kdim;k+=16){wmma::load_matrix_sync(a,w+(size_t)mt*kdim+k,kdim);wmma::load_matrix_sync(v,x+(size_t)k*npad+nt,npad);wmma::mma_sync(c,a,v,c);}__shared__ float z[256];wmma::store_matrix_sync(z,c,16,wmma::mem_row_major);__syncthreads();for(int q=threadIdx.x;q<256;q+=32){int r=q/16,s=q%16;if(mt+r<co&&nt+s<n){float t=z[q]+b[mt+r];y[(size_t)(mt+r)*n+nt+s]=relu?fmaxf(t,0):t;}}}
